B.Ls=new A.bE(B.M2,['BNPL \u064a\u0639\u0646\u064a "\u0627\u0634\u062a\u0631\u0650 \u0627\u0644\u0622\u0646 \u0648\u0627\u062f\u0641\u0639 \u0644\u0627\u062d\u0642\u0627\u064b" \u2014 \u0645\u062b\u0644 \u062a\u0645\u0627\u0631\u0627 \u0648\u062a\u0627\u0628\u064a. \u062a\u0642\u0633\u0651\u0645 \u0633\u0639\u0631 \u0627\u0644\u0645\u0646\u062a\u062c \u0639\u0644\u0649 \u062f\u0641\u0639\u0627\u062a \u0628\u062f\u0648\u0646 \u0641\u0648\u0627\u0626\u062f \u0638\u0627\u0647\u0631\u0629\u060c \u0628\u0633 \u0644\u0648 \u062a\u0631\u0627\u0643\u0645\u062a \u0639\u0644\u064a\u0643 \u0623\u0642\u0633\u0627\u0637 \u0643\u062b\u064a\u0631\u0629 \u0645\u0646 \u0623\u0643\u062b\u0631 \u0645\u0646 \u0645\u062a\u062c\u0631\u060c \u062a\u0644\u0642\u0649 \u0646\u0641\u0633\u0643 \u0645\u062f\u064a\u0646 \u0628\u0645\u0628\u0627\u0644\u063a \u0643\u0628\u064a\u0631\u0629 \u0628\u062f\u0648\u0646 \u0645\u0627 \u062a\u062d\u0633.',"\u0627\u0644\u062a\u0648\u0631\u0642 \u0637\u0631\u064a\u0642\u0629 \u062a\u0645\u0648\u064a\u0644 \u0645\u062a\u0648\u0627\u0641\u0642\u0629 \u0645\u0639 \u0627\u0644\u0634\u0631\u064a\u0639\u0629: \u062a\u0634\u062a\u0631\u064a \u0633\u0644\u0639\u0629 \u0628\u0627\u0644\u062a\u0642\u0633\u064a\u0637 \u0645\u0646 \u0627\u0644\u0628\u0646\u0643 \u062b\u0645 \u062a\u0628\u064a\u0639\u0647\u0627 \u0646\u0642\u062f\u0627\u064b \u0644\u062a\u062d\u0635\u0644 \u0639\u0644\u0649 \u0643\u0627\u0634. \u0645\u0641\u064a\u062f\u0629 \u0648\u0642\u062a \u0627\u0644\u062d\u0627\u062c\u0629\u060c \u0628\u0633 \u062a\u0628\u0642\u0649 \u062f\u064a\u0646 \u0644\u0627\u0632\u0645 \u062a\u0633\u062f\u062f\u0647 \u0628\u0627\u0644\u0623\u0642\u0633\u0627\u0637.","\u0627\u0644\u0627\u062f\u062e\u0627\u0631 \u064a\u0639\u0646\u064a \u062a\u062d\u062c\u0632 \u062c\u0632\u0621 \u0645\u0646 \u062f\u062e\u0644\u0643 \u0642\u0628\u0644 \u0645\u0627 \u062a\u0635\u0631\u0641\u0647\u060c \u062d\u062a\u0649 \u0644\u0648 \u0645\u0628\u0644\u063a \u0628\u0633\u064a\u0637 \u0634\u0647\u0631\u064a\u0627\u064b. \u0627\u0644\u0642\u0627\u0639\u062f\u0629 \u0627\u0644\u0630\u0647\u0628\u064a\u0629: \u0627\u062f\u0641\u0639 \u0644\u0646\u0641\u0633\u0643 \u0623\u0648\u0644\u0627\u064b \u2014 \u062d\u0648\u0651\u0644 \u0645\u0628\u0644\u063a \u062b\u0627\u0628\u062a \u0644\u062d\u0633\u0627\u0628 \u062a\u0648\u0641\u064a\u0631 \u0623\u0648\u0644 \u0645\u0627 \u064a\u062f\u062e\u0644 \u0627\u0644\u0631\u0627\u062a\u0628.","\u0627\u0644\u0627\u0633\u062a\u062b\u0645\u0627\u0631 \u064a\u0639\u0646\u064a \u062a\u0634\u063a\u0651\u0644 \u0641\u0644\u0648\u0633\u0643 \u0644\u062a\u0646\u0645\u0648 \u0645\u0639 \u0627\u0644\u0648\u0642\u062a \u0628\u062f\u0644 \u0645\u0627 \u062a\u0628\u0642\u0649 \u0633\u0627\u0643\u0646\u0629\u060c \u0645\u062b\u0644 \u0627\u0644\u0623\u0633\u0647\u0645 \u0623\u0648 \u0627\u0644\u0635\u0646\u0627\u062f\u064a\u0642. \u0641\u064a\u0647 \u0645\u062e\u0627\u0637\u0631\u0629\u060c \u0641\u0627\u0628\u062f\u0623 \u0628\u0645\u0628\u0644\u063a \u0635\u063a\u064a\u0631 \u062a\u0642\u062f\u0631 \u062a\u062a\u062d\u0645\u0651\u0644 \u062e\u0633\u0627\u0631\u062a\u0647 \u0648\u062a\u0639\u0644\u0651\u0645 \u0628\u0627\u0644\u062a\u062f\u0631\u064a\u062c.","\u0627\u0644\u0645\u064a\u0632\u0627\u0646\u064a\u0629 \u0627\u0644\u0634\u062e\u0635\u064a\u0629 \u064a\u0639\u0646\u064a \u062a\u0639\u0631\u0641 \u0648\u064a\u0646 \u062a\u0631\u0648\u062d \u0641\u0644\u0648\u0633\u0643 \u0642\u0628\u0644 \u0645\u0627 \u062a\u0631\u0648\u062d \u2014 \u062a\u0642\u0633\u0651\u0645 \u0631\u0627\u062a\u0628\u0643 \u0623\u0648\u0644 \u0627\u0644\u0634\u0647\u0631: \u0627\u0644\u062a\u0632\u0627\u0645\u0627\u062a \u062b\u0627\u0628\u062a\u0629\u060c \u0645\u0635\u0627\u0631\u064a\u0641 \u064a\u0648\u0645\u064a\u0629\u060c \u0648\u0627\u062f\u062e\u0627\u0631. \u0645\u062b\u0627\u0644 \u0628\u0633\u064a\u0637: \u0642\u0627\u0639\u062f\u0629 50/30/20 \u2014 \u0646\u0635\u0641 \u0627\u0644\u0631\u0627\u062a\u0628 \u0644\u0644\u0636\u0631\u0648\u0631\u064a\u0627\u062a\u060c 30% \u0644\u0631\u063a\u0628\u0627\u062a\u0643\u060c \u064820% \u062a\u0648\u0641\u064a\u0631 \u0648\u0633\u062f\u0627\u062f \u062f\u064a\u0648\u0646.","\u0646\u0633\u0628\u0629 \u0627\u0644\u062f\u064a\u0646 \u0625\u0644\u0649 \u0627\u0644\u062f\u062e\u0644 \u062a\u0642\u064a\u0633 \u0643\u0645 \u0645\u0646 \u0631\u0627\u062a\u0628\u0643 \u064a\u0631\u0648\u062d \u0644\u0633\u062f\u0627\u062f \u0627\u0644\u0623\u0642\u0633\u0627\u0637 \u0648\u0627\u0644\u062f\u064a\u0648\u0646 \u0643\u0644 \u0634\u0647\u0631. \u0645\u062b\u0627\u0644: \u0631\u0627\u062a\u0628\u0643 8000 \u0648\u0623\u0642\u0633\u0627\u0637\u0643 2000 \u064a\u0639\u0646\u064a \u0646\u0633\u0628\u062a\u0643 25%. \u0643\u0644 \u0645\u0627 \u0632\u0627\u062f\u062a \u0627\u0644\u0646\u0633\u0628\u0629 \u0639\u0646 \u0627\u0644\u062b\u0644\u062b\u060c \u0635\u0627\u0631 \u0648\u0636\u0639\u0643 \u0623\u062e\u0637\u0631 \u0648\u0642\u0644\u0651\u062a \u0642\u062f\u0631\u062a\u0643 \u0639\u0644\u0649 \u0627\u0644\u062a\u062d\u0645\u0651\u0644 \u0644\u0648 \u0635\u0627\u0631 \u0637\u0627\u0631\u0626."],t.li)
